import React from 'react';
import { useApp } from '../context/AppContext';
import MessageCard from './MessageCard';
import '../styles/globals.css';

const MessageList: React.FC = () => {
  const { state } = useApp();

  // Filtrar itens baseado na busca e filtro
  const filteredItems = state.items.filter(item => {
    const matchesSearch = state.searchQuery === '' || 
      item.name.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
      item.subject.toLowerCase().includes(state.searchQuery.toLowerCase());

    const matchesFilter = state.filter === 'all' || 
      (state.filter === 'unread' && !item.subject.includes('[LIDO]'));

    return matchesSearch && matchesFilter;
  });

  if (state.loading) {
    return (
      <div className="flex-1 overflow-auto p-4">
        <div className="space-y-3">
          {[...Array(5)].map((_, index) => (
            <div key={index} className="card p-4">
              <div className="flex items-center gap-3">
                <div className="skeleton w-5 h-5 rounded"></div>
                <div className="flex-1 space-y-2">
                  <div className="skeleton h-4 w-1/3 rounded"></div>
                  <div className="skeleton h-3 w-2/3 rounded"></div>
                </div>
                <div className="skeleton h-3 w-16 rounded"></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (!state.selectedMenuId) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div 
          className="text-center"
          style={{ color: 'var(--color-text-muted)' }}
        >
          <div className="text-lg font-medium mb-2">Nenhuma pasta selecionada</div>
          <div className="text-sm">Selecione uma pasta para ver as mensagens</div>
        </div>
      </div>
    );
  }

  if (filteredItems.length === 0) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div 
          className="text-center"
          style={{ color: 'var(--color-text-muted)' }}
        >
          <div className="text-lg font-medium mb-2">Nenhuma mensagem encontrada</div>
          <div className="text-sm">
            {state.searchQuery ? 'Tente uma busca diferente' : 'Esta pasta está vazia'}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-auto">
      <div className="divide-y" style={{ borderColor: 'var(--color-border)' }}>
        {filteredItems.map((item) => (
          <MessageCard 
            key={item.id} 
            item={item}
            isAnySelected={state.selectedItems.length > 0}
          />
        ))}
      </div>
    </div>
  );
};

export default MessageList;
